import anthropic
import json
import re

client = anthropic.Anthropic()

# --- Pure functions (no LLM) ---
def validate_email(email: str) -> dict:
    ok = bool(re.match(r"^[^@]+@[^@]+\.[^@]+$", email))
    return {"valid": ok, "email": email}

def create_account(email: str, name: str) -> dict:
    # Stub: in production, write to DB
    user_id = f"USR-{abs(hash(email)) % 10000:04d}"
    return {"ok": True, "user_id": user_id, "email": email, "name": name}

def send_email(to: str, subject: str, body: str) -> dict:
    print(f"[EMAIL] To: {to}\n  Subject: {subject}\n  Body: {body[:80]}...")
    return {"ok": True}

# --- LLM step: generate personalized welcome email body ---
def write_welcome_email(name: str, product: str) -> str:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        messages=[{"role": "user", "content":
            f"Write a brief, warm welcome email body for {name} who just joined {product}. "
            f"2-3 sentences. No subject line. No signature."}],
    )
    return resp.content[0].text.strip()

# --- Workflow: fixed sequence in code ---
def onboard_customer_workflow(email: str, name: str, product: str) -> dict:
    # Step 1: validate (no LLM)
    validation = validate_email(email)
    if not validation["valid"]:
        return {"status": "error", "reason": f"Invalid email: {email}"}

    # Step 2: create account (no LLM)
    account = create_account(email, name)
    if not account["ok"]:
        return {"status": "error", "reason": "Account creation failed"}

    # Step 3: generate welcome email body (LLM)
    body = write_welcome_email(name, product)

    # Step 4: send email (no LLM)
    send_email(to=email, subject=f"Welcome to {product}!", body=body)

    return {"status": "complete", "user_id": account["user_id"]}

result = onboard_customer_workflow(
    email="alice@example.com", name="Alice", product="Acme SaaS"
)
print(result)
# Output: {"status": "complete", "user_id": "USR-1234"}

from collections import Counter

# Suppose we have a log of tool-call sequences from an agent run on 1,000 invoice tasks:
AGENT_LOGS = [
    ["get_invoice", "task_complete"],                        # 480 runs
    ["get_invoice", "get_customer", "task_complete"],        # 310 runs
    ["get_invoice", "issue_refund", "task_complete"],        # 120 runs
    ["get_invoice", "get_customer", "issue_refund", "task_complete"],  # 55 runs
    ["get_invoice", "search_knowledge_base", "task_complete"],         # 20 runs
    # ... many other rare paths
]

def analyze_paths(logs: list[list[str]], top_n: int = 3) -> list:
    counts = Counter(tuple(path) for path in logs)
    total = sum(counts.values())
    top = counts.most_common(top_n)
    return [
        {"path": list(path), "count": count, "pct": round(count / total * 100, 1)}
        for path, count in top
    ]

top_paths = analyze_paths(AGENT_LOGS)
for p in top_paths:
    print(f"{p['pct']}%: {' -> '.join(p['path'])}")
# 48.0%: get_invoice -> task_complete
# 31.0%: get_invoice -> get_customer -> task_complete
# 12.0%: get_invoice -> issue_refund -> task_complete
# Top 3 paths cover 91% of runs.

# The refactored hybrid:
import anthropic, json
client = anthropic.Anthropic()

CLASSIFIER_SYSTEM = """
Given an invoice support request, classify it as one of:
- "lookup_only": user just wants invoice information
- "lookup_with_customer": user needs customer details too
- "refund": user needs a refund
- "other": anything else
Return JSON: {"category": "..."}
"""

def classify_request(request: str) -> str:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001", max_tokens=50,
        system=CLASSIFIER_SYSTEM,
        messages=[{"role": "user", "content": request}],
    )
    try:
        return json.loads(resp.content[0].text).get("category", "other")
    except json.JSONDecodeError:
        return "other"

def handle_invoice_request(request: str, invoice_id: str) -> dict:
    category = classify_request(request)

    if category == "lookup_only":
        # Fast workflow path: 1 function call
        return {"result": f"Invoice {invoice_id} fetched", "path": "workflow:lookup_only"}

    elif category == "lookup_with_customer":
        # Fast workflow path: 2 function calls
        return {"result": f"Invoice {invoice_id} + customer fetched", "path": "workflow:lookup_with_customer"}

    elif category == "refund":
        # Fast workflow path with approval gate
        return {"result": f"Refund issued for {invoice_id}", "path": "workflow:refund"}

    else:
        # Fallback to agent for rare/unknown paths
        return {"result": "Handled by agent", "path": "agent:fallback"}

print(handle_invoice_request("What is the status of my invoice?", "INV-001"))
# {"result": "Invoice INV-001 fetched", "path": "workflow:lookup_only"}
